1553   const unsigned OpCode = NarrowUse->getOpcode();
1554   // Only Add/Sub/Mul instructions are supported.
1555   if (OpCode != Instruction::Add && OpCode != Instruction::Sub &&
1556       OpCode != Instruction::Mul)
