1559   // The operand that is not defined by NarrowDef of DU. Let's call it the
1560   // other operand.
1561   assert((NarrowUse->getOperand(0) == NarrowDef ||
1562           NarrowUse->getOperand(1) == NarrowDef) &&
1563          "bad DU");
