1855   // truncating the IV first.
1856   if (widenLoopCompare(DU))
1857     return nullptr;
1858 
1859   // We are here about to generate a truncate instruction that may hurt
1860   // performance because the scalar evolution expression computed earlier
1861   // in WideAddRec.first does not indicate a polynomial induction expression.
1862   // In that case, look at the operands of the use instruction to determine
1863   // if we can still widen the use instead of truncating its operand.
1864   if (widenWithVariantUse(DU))
1865     return nullptr;
