1899 /// Process a single induction variable. First use the SCEVExpander to create a
1900 /// wide induction variable that evaluates to the same recurrence as the
1901 /// original narrow IV. Then use a worklist to forward traverse the narrow IV's
1902 /// def-use chain. After widenIVUse has processed all interesting IV users, the
1903 /// narrow IV will be isolated for removal by DeleteDeadPHIs.
1904 ///
1905 /// It would be simpler to delete uses as they are processed, but we must avoid
1906 /// invalidating SCEV expressions.
1907 PHINode *WidenIV::createWideIV(SCEVExpander &Rewriter) {
1908   // Is this phi an induction variable?
1909   const SCEVAddRecExpr *AddRec = dyn_cast<SCEVAddRecExpr>(SE->getSCEV(OrigPhi));
1910   if (!AddRec)
1911     return nullptr;
1912 
1913   // Widen the induction variable expression.
1914   const SCEV *WideIVExpr = getExtendKind(OrigPhi) == ExtendKind::Sign
1915                                ? SE->getSignExtendExpr(AddRec, WideType)
1916                                : SE->getZeroExtendExpr(AddRec, WideType);
1917 
1918   assert(SE->getEffectiveSCEVType(WideIVExpr->getType()) == WideType &&
1919          "Expect the new IV expression to preserve its type");
1920 
1921   // Can the IV be extended outside the loop without overflow?
1922   AddRec = dyn_cast<SCEVAddRecExpr>(WideIVExpr);
1923   if (!AddRec || AddRec->getLoop() != L)
1924     return nullptr;
1925 
1926   // An AddRec must have loop-invariant operands. Since this AddRec is
1927   // materialized by a loop header phi, the expression cannot have any post-loop
1928   // operands, so they must dominate the loop header.
1929   assert(
1930       SE->properlyDominates(AddRec->getStart(), L->getHeader()) &&
1931       SE->properlyDominates(AddRec->getStepRecurrence(*SE), L->getHeader()) &&
1932       "Loop header phi recurrence inputs do not dominate the loop");
1933 
1934   // Iterate over IV uses (including transitive ones) looking for IV increments
1935   // of the form 'add nsw %iv, <const>'. For each increment and each use of
1936   // the increment calculate control-dependent range information basing on
1937   // dominating conditions inside of the loop (e.g. a range check inside of the
1938   // loop). Calculated ranges are stored in PostIncRangeInfos map.
1939   //
1940   // Control-dependent range information is later used to prove that a narrow
1941   // definition is not negative (see pushNarrowIVUsers). It's difficult to do
1942   // this on demand because when pushNarrowIVUsers needs this information some
1943   // of the dominating conditions might be already widened.
1944   if (UsePostIncrementRanges)
1945     calculatePostIncRanges(OrigPhi);
1946 
1947   // The rewriter provides a value for the desired IV expression. This may
1948   // either find an existing phi or materialize a new one. Either way, we
1949   // expect a well-formed cyclic phi-with-increments. i.e. any operand not part
1950   // of the phi-SCC dominates the loop entry.
1951   Instruction *InsertPt = &*L->getHeader()->getFirstInsertionPt();
1952   Value *ExpandInst = Rewriter.expandCodeFor(AddRec, WideType, InsertPt);
1953   // If the wide phi is not a phi node, for example a cast node, like bitcast,
1954   // inttoptr, ptrtoint, just skip for now.
1955   if (!(WidePhi = dyn_cast<PHINode>(ExpandInst))) {
1956     // if the cast node is an inserted instruction without any user, we should
1957     // remove it to make sure the pass don't touch the function as we can not
1958     // wide the phi.
1959     if (ExpandInst->hasNUses(0) &&
1960         Rewriter.isInsertedInstruction(cast<Instruction>(ExpandInst)))
1961       DeadInsts.emplace_back(ExpandInst);
1962     return nullptr;
1963   }
1964 
1965   // Remembering the WideIV increment generated by SCEVExpander allows
1966   // widenIVUse to reuse it when widening the narrow IV's increment. We don't
1967   // employ a general reuse mechanism because the call above is the only call to
1968   // SCEVExpander. Henceforth, we produce 1-to-1 narrow to wide uses.
1969   if (BasicBlock *LatchBlock = L->getLoopLatch()) {
1970     WideInc =
1971         dyn_cast<Instruction>(WidePhi->getIncomingValueForBlock(LatchBlock));
1972     if (WideInc) {
1973       WideIncExpr = SE->getSCEV(WideInc);
1974       // Propagate the debug location associated with the original loop
1975       // increment to the new (widened) increment.
1976       auto *OrigInc =
1977           cast<Instruction>(OrigPhi->getIncomingValueForBlock(LatchBlock));
1978       WideInc->setDebugLoc(OrigInc->getDebugLoc());
1979     }
1980   }
1981 
1982   LLVM_DEBUG(dbgs() << "Wide IV: " << *WidePhi << "\n");
1983   ++NumWidened;
1984 
1985   // Traverse the def-use chain using a worklist starting at the original IV.
1986   assert(Widened.empty() && NarrowIVUsers.empty() && "expect initial state" );
1987 
1988   Widened.insert(OrigPhi);
1989   pushNarrowIVUsers(OrigPhi, WidePhi);
1990 
1991   while (!NarrowIVUsers.empty()) {
1992     WidenIV::NarrowIVDefUse DU = NarrowIVUsers.pop_back_val();
1993 
1994     // Process a def-use edge. This may replace the use, so don't hold a
1995     // use_iterator across it.
1996     Instruction *WideUse = widenIVUse(DU, Rewriter);
1997 
1998     // Follow all def-use edges from the previous narrow use.
1999     if (WideUse)
2000       pushNarrowIVUsers(DU.NarrowUse, WideUse);
2001 
2002     // widenIVUse may have removed the def-use edge.
2003     if (DU.NarrowDef->use_empty())
2004       DeadInsts.emplace_back(DU.NarrowDef);
2005   }
2006 
2007   // Attach any debug information to the new PHI.
2008   replaceAllDbgUsesWith(*OrigPhi, *WidePhi, *WidePhi, *DT);
2009 
2010   return WidePhi;
2011 }
