2013 /// Calculates control-dependent range for the given def at the given context
2014 /// by looking at dominating conditions inside of the loop
2015 void WidenIV::calculatePostIncRange(Instruction *NarrowDef,
2016                                     Instruction *NarrowUser) {
2017   using namespace llvm::PatternMatch;
2018 
2019   Value *NarrowDefLHS;
2020   const APInt *NarrowDefRHS;
2021   if (!match(NarrowDef, m_NSWAdd(m_Value(NarrowDefLHS),
2022                                  m_APInt(NarrowDefRHS))) ||
2023       !NarrowDefRHS->isNonNegative())
2024     return;
2025 
2026   auto UpdateRangeFromCondition = [&] (Value *Condition,
2027                                        bool TrueDest) {
2028     CmpInst::Predicate Pred;
2029     Value *CmpRHS;
2030     if (!match(Condition, m_ICmp(Pred, m_Specific(NarrowDefLHS),
2031                                  m_Value(CmpRHS))))
2032       return;
2033 
2034     CmpInst::Predicate P =
2035             TrueDest ? Pred : CmpInst::getInversePredicate(Pred);
2036 
2037     auto CmpRHSRange = SE->getSignedRange(SE->getSCEV(CmpRHS));
2038     auto CmpConstrainedLHSRange =
2039             ConstantRange::makeAllowedICmpRegion(P, CmpRHSRange);
2040     auto NarrowDefRange = CmpConstrainedLHSRange.addWithNoWrap(
2041         *NarrowDefRHS, OverflowingBinaryOperator::NoSignedWrap);
2042 
2043     updatePostIncRangeInfo(NarrowDef, NarrowUser, NarrowDefRange);
2044   };
2045 
2046   auto UpdateRangeFromGuards = [&](Instruction *Ctx) {
2047     if (!HasGuards)
2048       return;
2049 
2050     for (Instruction &I : make_range(Ctx->getIterator().getReverse(),
2051                                      Ctx->getParent()->rend())) {
2052       Value *C = nullptr;
2053       if (match(&I, m_Intrinsic<Intrinsic::experimental_guard>(m_Value(C))))
2054         UpdateRangeFromCondition(C, /*TrueDest=*/true);
2055     }
2056   };
